import { useState, useEffect, useCallback } from 'react';
import { api, apiPost } from '../utils/api';
import { prefetch } from '../utils/prefetch';

// Normalize raw strategy data from API into display-ready shape
function normalizeStrategies(data) {
  const raw = Array.isArray(data) ? data : data?.strategies || [];
  return raw.map(s => {
    const apiStats = s.stats || {};
    // avg_win_rate from backend is decimal (0.55); convert to percentage for display
    const rawWr = apiStats.avg_win_rate ?? s.win_rate ?? s.winrate ?? null;
    const winRate = rawWr != null ? (rawWr <= 1 ? Math.round(rawWr * 100) : rawWr) : null;
    const sharpe = apiStats.avg_sharpe ?? s.sharpe ?? s.sharpe_ratio ?? null;
    return {
      ...s,
      label: s.label || s.display_name || s.name || s.key || 'Unnamed',
      stats: {
        ...apiStats,
        avg_win_rate: winRate,
        avg_return: apiStats.avg_return ?? s.avg_r ?? null,
        avg_sharpe: sharpe,
        total_trades: apiStats.total_trades ?? s.trades ?? s.total_trades ?? 0,
        avg_score: apiStats.avg_score ?? sharpe ?? null,
        symbols_tested: apiStats.symbols_tested ?? 0,
        max_drawdown: apiStats.max_drawdown ?? s.max_drawdown ?? s.drawdown ?? null,
        cagr: apiStats.cagr ?? s.cagr ?? null,
        total_return: apiStats.total_return ?? s.total_return ?? null,
        profit_factor: apiStats.profit_factor ?? s.profit_factor ?? s.avg_pf ?? null,
      },
    };
  });
}

export default function useStrategies(assetClass = 'us') {
  // Seed from prefetch cache for instant first render
  const cached = assetClass === 'us' ? prefetch.get('strategies') : null;
  const [strategies, setStrategies] = useState(() => cached ? normalizeStrategies(cached) : []);
  const [loading, setLoading] = useState(!cached);

  const refresh = useCallback(async () => {
    setLoading(true);
    const data = await api(`/strategies?asset_class=${encodeURIComponent(assetClass)}`);
    if (data) {
      setStrategies(normalizeStrategies(data));
    }
    setLoading(false);
  }, [assetClass]);

  useEffect(() => {
    refresh();
  }, [refresh]);

  const promoteStrategy = useCallback(async (name) => {
    const result = await apiPost('/strategies/' + encodeURIComponent(name) + '/promote');
    if (result) { await refresh(); return true; }
    return false;
  }, [refresh]);

  const suppressStrategy = useCallback(async (name) => {
    const result = await apiPost('/strategies/' + encodeURIComponent(name) + '/suppress');
    if (result) { await refresh(); return true; }
    return false;
  }, [refresh]);

  return { strategies, loading, promoteStrategy, suppressStrategy, refresh };
}
